### Literal Types

Literal types represent specific values rather than general types. They can be strings, numbers, or booleans.

### String Literal Types

```typescript
type Direction = "north" | "south" | "east" | "west";
type Status = "active" | "inactive" | "pending";

let dir: Direction = "north";
// dir = "up"; // Error
```

### Numeric Literal Types

```typescript
type DiceRoll = 1 | 2 | 3 | 4 | 5 | 6;
type Port = 3000 | 8080 | 443;

let roll: DiceRoll = 4;
// roll = 7; // Error
```

### Boolean Literal Types

```typescript
type True = true;
type False = false;

let isComplete: True = true;
// isComplete = false; // Error
```

### Combining with Union Types

```typescript
type Result = "success" | "failure" | 0 | 1;
```

### Template Literal Types (TypeScript 4.1+)

```typescript
type EventName = `on${Capitalize<string>}`;
type Color = "red" | "green" | "blue";
type DarkColor = `dark${Capitalize<Color>}`;
// "darkRed" | "darkGreen" | "darkBlue"
```

### const Assertions

```typescript
const config = {
  server: "localhost",
  port: 3000
} as const;
// Type is: { readonly server: "localhost"; readonly port: 3000 }
```

> **Key Point:** Literal types enable precise type checking with specific values.

codeExample:
// String literal types
type HTTPMethod = "GET" | "POST" | "PUT" | "DELETE" | "PATCH";
type LogLevel = "debug" | "info" | "warn" | "error";

function request(method: HTTPMethod, url: string): void {
  console.log(`${method} ${url}`);
}

request("GET", "/api/users");

// Numeric literal
type Weekday = 0 | 1 | 2 | 3 | 4 | 5 | 6;

function isWeekend(day: Weekday): boolean {
  return day === 0 || day === 6;
}

// Const assertion for literal inference
const Colors = ["red", "green", "blue"] as const;
type Color = (typeof Colors)[number]; // "red" | "green" | "blue"
